// @ts-nocheck
import { Copy, Terminal } from 'lucide-react';
import { notify, notifyError } from '../../lib/notify';
import { sendSqlToTerminal } from '../../lib/sendSqlToTerminal';

export function SqlScriptActions({
  sql,
  connectionId,
  database,
  copyLabel = 'Copiar',
  showTerminal = true,
}) {
  const text = String(sql ?? '').trim();
  if (!text) return null;

  const onCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      notify('Copiado al portapapeles');
    } catch {
      notifyError(new Error('No se pudo copiar'));
    }
  };

  const onTerminal = () => {
    if (!connectionId) {
      notifyError(new Error('No hay conexión activa para el terminal'));
      return;
    }
    sendSqlToTerminal({ connectionId, database, sql: text });
  };

  return (
    <div className="flex flex-wrap gap-1">
      <button type="button" className="nv-btn !text-2xs" onClick={onCopy}>
        <Copy size={10} /> {copyLabel}
      </button>
      {showTerminal && connectionId && (
        <button type="button" className="nv-btn !text-2xs" onClick={onTerminal}>
          <Terminal size={10} /> Enviar al Terminal SQL
        </button>
      )}
    </div>
  );
}
